return ['project-id-version'=>'BravesChat 2.4.6','report-msgid-bugs-to'=>'https://wordpress.org/support/plugin/braveschat','pot-creation-date'=>'2026-04-22T16:25:29+00:00','po-revision-date'=>'2026-04-22 20:24+0000','last-translator'=>'','language-team'=>'Español','language'=>'es_ES','mime-version'=>'1.0','content-type'=>'text/plain; charset=UTF-8','content-transfer-encoding'=>'8bit','plural-forms'=>'nplurals=2; plural=(n != 1);','x-generator'=>'Loco https://localise.biz/','x-domain'=>'braveschat','x-loco-version'=>'2.8.3; wp-6.9.4; php-8.3.28','messages'=>['BravesChat'=>'BravesChat','https://github.com/Carlos-Vera/BravesChat'=>'https://github.com/Carlos-Vera/BravesChat','A professional tool that connects your website to your N8N agent, allowing you to provide AI-powered support directly on your website.'=>'Una herramienta profesional que conecta tu sitio web con tu agente de N8N, lo que te permite ofrecer asistencia basada en inteligencia artificial directamente en tu sitio web.','Carlos Vera'=>'Carlos Vera','https://braveslab.com'=>'https://braveslab.com','Your AI agent'=>'Tu agente de IA','I am here to help you'=>'Estoy aquí para ayudarte','Hello! How can I help you today?'=>'¡Hola! ¿En qué puedo ayudarte hoy?','Our business hours are from 9:00 to 18:00. Leave us your message and we will get back to you as soon as possible.'=>'Nuestro horario de atención es de 9:00 a 18:00. Déjanos un mensaje y nos pondremos en contacto contigo lo antes posible.','This site uses cookies to improve your experience. By continuing to browse, you accept our cookie policy.'=>'Este sitio web utiliza cookies para mejorar tu experiencia. Al continuar navegando, aceptas nuestra política de cookies.','Accept'=>'Aceptar
','Dashboard'=>'Cuadro de mandos','Ajustes'=>'Ajustes','Support Chat'=>'Chat de asistencia','We are here to help you'=>'Estamos aquí para ayudarle','Hello! How can we help you today?'=>'Hola, ¿en qué podemos ayudarle hoy?','BravesChat iA'=>'BravesChat iA','Settings'=>'Ajustes','Appearance'=>'Apariencia','Schedules'=>'Horarios','GDPR'=>'GDPR','About'=>'Acerca de','History'=>'Historia','Agent'=>'Agente','Empty chat or invalid format.'=>'Chat vacío o formato no válido.','Could not display the conversation.'=>'No se ha podido visualizar la conversación.','No conversation data.'=>'No hay datos de conversación.','Anonymous Conversation'=>'Conversación anónima','Session'=>'Sesión','User'=>'Usuario','Overview'=>'Visión general','View plugin information'=>'Ver información del plugin','Save'=>'Guardar','Back to top'=>'Volver arriba','Availability'=>'Disponibilidad','Privacy'=>'Privacidad','Conversations'=>'Conversaciones','You do not have permission to access this page.'=>'No tiene permiso para acceder a esta página.','About <strong>BravesChat iA</strong>'=>'Acerca de <strong>BravesChat iA</strong>','Plugin information and changelog.'=>'Información sobre el plugin y registro de cambios.','Plugin Information'=>'Información sobre plugins','Version'=>'Versión','Last Update: <b>Apr 15, 2026</b>'=>'Última actualización: <b>15 de abril de 2026</b>','Lead Author'=>'Autor principal','Company'=>'Empresa','Changelog'=>'Registro de cambios','Today'=>'Hoy','Safer links, translatable history'=>'Enlaces más seguros, historia traducible','Security'=>'Seguridad','Links from your agent only open if they point to http:// or https://. Anything else — javascript:, data: — is ignored.'=>'Los enlaces de su agente sólo se abren si apuntan a http:// o https://. Cualquier otra cosa - javascript:, data: - se ignora.','The N8N auth header is cleaned before it leaves WordPress. Characters that could alter the request are stripped out.'=>'La cabecera N8N auth se limpia antes de salir de WordPress. Se eliminan los caracteres que puedan alterar la solicitud.','New Features'=>'Novedades','WordPress in English? The daily verse in the panel header shows in English too — 365 NIV entries, loaded locally.'=>'¿WordPress en inglés? El versículo diario en la cabecera del panel se muestra también en inglés - 365 entradas NVI, cargadas localmente.','Improvements'=>'Mejoras','The conversation viewer now speaks your language. Contact name, session ID, and sender labels follow your WordPress locale — no more hardcoded Spanish.'=>'El visor de conversaciones ahora habla tu idioma. El nombre del contacto, el identificador de sesión y las etiquetas de remitente siguen la configuración regional de WordPress.','Adding a new version to this page no longer means adjusting spacing by hand. The layout figures itself out.'=>'Para añadir una nueva versión a esta página ya no es necesario ajustar el espaciado a mano. La maquetación se hace sola.','Apr 16, 2026'=>'16 de abril de 2026','Apr 15, 2026'=>'15 de abril de 2026','Local verses, English UI, security fixes'=>'Versiones locales, interfaz de usuario en inglés, correcciones de seguridad','ADDED: Bible verses now load from a local file — no external API calls, no rate limits, no dependency on scripture.api.bible.'=>'AÑADIDO: Los versículos de la Biblia ahora se cargan desde un archivo local - sin llamadas API externas, sin límites de velocidad, sin dependencia de scripture.api.bible.','ADDED: Full English translation of the admin panel and chat widget, with es_ES support via .po/.mo files.'=>'AÑADIDO: Traducción completa al inglés del panel de administración y del widget de chat, con soporte es_ES mediante archivos .po/.mo.','FIXED: The N8N auth token no longer leaks through console.log in the browser.'=>'CORREGIDO: El auth token de N8N ya no se filtra a través de console.log en el navegador.','FIXED: HTTP/HTTPS scheme validated before every wp_remote_get() call.'=>'CORREGIDO: Esquema HTTP/HTTPS validado antes de cada llamada a wp_remote_get().','Bug Fixes'=>'Corrección de errores','FIXED: $_GET[\'page\'] sanitized and boolean values properly escaped in hidden form inputs.'=>'ARREGLADO: $_GET[\'page\'] saneado y valores booleanos correctamente escapados en entradas de formularios ocultos.','FIXED: admin.js i18n pattern updated to const { __ } = wp.i18n — compatible with wp i18n make-json.'=>'ARREGLADO: patrón i18n de admin.js actualizado a const { __ } = wp.i18n - compatible con wp i18n make-json.','Apr 12, 2026'=>'12 de abril de 2026','The plugin in your language'=>'El plugin en su idioma','IMPROVED: If your WordPress is not in Spanish, the panel and chat adapt automatically — buttons, widget text, and labels included.'=>'MEJORADO: Si tu WordPress no está en español, el panel y el chat se adaptan automáticamente - botones, texto del widget y etiquetas incluidas.','FIXED: Some chat texts always appeared in Spanish regardless of the site language. Not anymore.'=>'CORREGIDO: Algunos textos del chat aparecían siempre en español independientemente del idioma del sitio. Ahora ya no.','Mixed mode and dark mode compatibility'=>'Compatibilidad con modo mixto y modo oscuro','ADDED: New "Mixed" display mode — the chat appears as a floating bubble across the entire site and as full screen on pages where you add the Gutenberg block.'=>'AÑADIDO: Nuevo modo de visualización "Mixto": el chat aparece como una burbuja flotante en todo el sitio y como pantalla completa en las páginas en las que se añade el bloque Gutenberg.','FIXED: In iOS Safari with dark mode active, chat colors no longer invert — the widget always keeps its original design.'=>'CORREGIDO: En iOS Safari con el modo oscuro activo, los colores del chat ya no se invierten, el widget siempre mantiene su diseño original.','FIXED: The GDPR privacy banner no longer inherits colors from dark mode themes — text stays readable on any theme.'=>'CORREGIDO: El banner de privacidad GDPR ya no hereda los colores de los temas en modo oscuro - el texto se mantiene legible en cualquier tema.','FIXED: Opening the chat in full screen no longer shows a white background flash before the interface loads.'=>'CORREGIDO: Al abrir el chat en pantalla completa ya no aparece un flash de fondo blanco antes de que se cargue la interfaz.','Mar 26, 2026'=>'26 de marzo de 2026','Dark mode for the admin panel'=>'Modo oscuro para el panel de administración','ADDED: The admin panel now has dark mode. (My obsession with protecting my eyes.) Toggle it with one button — your preference is saved and applied instantly, with no flash on load.'=>'AÑADIDO: El panel de administración ahora tiene modo oscuro. (Mi obsesión con la protección de mis ojos.) Alternar con un botón - su preferencia se guarda y se aplica al instante, sin flash en la carga.','ADDED: The welcome message editor also switches to dark mode along with the rest of the panel.'=>'AÑADIDO: El editor de mensajes de bienvenida también cambia a modo oscuro junto con el resto del panel.','IMPROVED: The entire panel design switches automatically when dark mode is active — no exceptions, no hardcoded colors.'=>'MEJORADO: Todo el diseño del panel cambia automáticamente cuando el modo oscuro está activo, sin excepciones ni colores codificados.','IMPROVED: The excluded pages selection buttons now look consistent with the rest of the panel.'=>'MEJORADO: Los botones de selección de páginas excluidas ahora tienen un aspecto coherente con el resto del panel.','Native mobile chat'=>'Chat móvil nativo','ADDED: On mobile, the chat now takes the full screen. It has its own header with a close button, respects the iPhone notch, and blocks background scroll while open.'=>'AÑADIDO: En los móviles, el chat ocupa ahora toda la pantalla. Tiene su propia cabecera con un botón de cierre, respeta la muesca del iPhone y bloquea el desplazamiento del fondo mientras está abierto.','IMPROVED: The widget no longer interferes with WooCommerce cart or checkout — z-index adjusted to coexist without conflicts.'=>'MEJORADO: El widget ya no interfiere con el carrito o checkout de WooCommerce - z-index ajustado para coexistir sin conflictos.','IMPROVED: Panel scripts load via the WordPress system instead of being embedded in templates — better compatibility and security.'=>'MEJORADO: Los scripts del panel se cargan a través del sistema WordPress en lugar de estar incrustados en las plantillas - mejor compatibilidad y seguridad.','Mar 25, 2026'=>'25 de marzo de 2026','Mar 18, 2026'=>'18 de marzo de 2026','Verse of the day'=>'Versículo del día','ADDED: A Bible verse (NIV) appears every day in the panel header. It changes at midnight automatically — no configuration needed. Fetched from the American Bible Society API with a 24h WordPress transient cache. Fully safe, no user data collected.'=>'AÑADIDO: Cada día aparece un versículo de la Biblia (NVI) en la cabecera del panel. Cambia a medianoche automáticamente - sin necesidad de configuración. Obtenido de la API de la Sociedad Bíblica Americana con una caché transitoria de WordPress de 24 horas. Totalmente seguro, no se recogen datos del usuario.','UX/UI design improvements'=>'Mejoras en el diseño UX/UI','Experience Improvements'=>'Mejoras en la experiencia','IMPROVED: On mobile, the bubble takes less space. The default skin shrinks to 48×48px; the Braves skin collapses to avatar + round button. Desktop is unchanged.'=>'MEJORADO: En móviles, la burbuja ocupa menos espacio. El skin por defecto se reduce a 48×48px; el skin Braves se contrae a avatar + botón redondo. En escritorio no hay cambios.','IMPROVED: Webhook and save notices move to the header. The page stays clean.'=>'MEJORADO: Los avisos de webhook y guardar se mueven a la cabecera. La página se mantiene limpia.','IMPROVED: Sidebar renamed — Availability, Privacy, Conversations. More direct.'=>'MEJORADO: Barra lateral renombrada - Disponibilidad, Privacidad, Conversaciones. Más directo.','IMPROVED: The version badge highlights when you are on this page.'=>'MEJORADO: La insignia de la versión se resalta cuando estás en esta página.','FIXED: The custom image upload button in Appearance now correctly opens the WordPress Media Library.'=>'CORREGIDO: El botón de carga de imágenes personalizadas en Apariencia ahora abre correctamente la biblioteca multimedia de WordPress.','FIXED: WordPress.org Plugin Check no longer reports text domain errors. The plugin uses the correct slug (braveschat) in all files and in the distribution ZIP.'=>'CORREGIDO: WordPress.org Plugin Check ya no informa de errores de dominio de texto. El plugin utiliza el slug correcto (braveschat) en todos los archivos y en el ZIP de distribución.','Type while the agent responds'=>'Escriba mientras el agente responde','IMPROVED: The text field no longer locks while the agent responds. You can type at any time. If the agent is mid-response, it cancels and your new message is sent immediately.'=>'MEJORADO: El campo de texto ya no se bloquea mientras el agente responde. Puede escribir en cualquier momento. Si el agente está a mitad de respuesta, se cancela y tu nuevo mensaje se envía inmediatamente.','Mar 11, 2026'=>'11 de marzo de 2026','Mar 10, 2026'=>'10 de marzo de 2026','The token lives on the server'=>'El token vive en el servidor','ADDED: The N8N token no longer travels to the browser. The frontend sends the message to WordPress, and WordPress forwards it to the webhook with the token added server-side — invisible to any visitor.'=>'AÑADIDO: El token N8N ya no viaja al navegador. El frontend envía el mensaje a WordPress, y WordPress lo reenvía al webhook con el token añadido del lado del servidor - invisible para cualquier visitante.','ADDED: Three authentication methods for N8N: custom header, Basic Auth, or none.'=>'AÑADIDO: Tres métodos de autenticación para N8N: encabezado personalizado, autenticación básica o ninguno.','IMPROVED: The active display mode (modal or full screen) now appears in the panel header.'=>'MEJORADO: El modo de visualización activo (modal o pantalla completa) aparece ahora en la cabecera del panel.','IMPROVED: The Gutenberg block shows a redesigned preview matching the panel style.'=>'MEJORADO: El bloque Gutenberg muestra una vista previa rediseñada que coincide con el estilo del panel.','IMPROVED: GPL-2.0-or-later license, aligned with WordPress.org requirements.'=>'MEJORADO: Licencia GPL-2.0 o posterior, alineada con los requisitos de WordPress.org.','IMPROVED: Banners, screenshots, and icons converted to PNG for maximum compatibility.'=>'MEJORADO: Banners, capturas de pantalla e iconos convertidos a PNG para máxima compatibilidad.','Mar 5, 2026'=>'5 de marzo de 2026','Plugin details without leaving the admin'=>'Detalles del plugin sin salir de la administración','ADDED: Click "View details" in the WordPress plugins list to see the full plugin card: screenshots, FAQ, instructions, and compatibility.'=>'AÑADIDO: Haga clic en "Ver detalles" en la lista de plugins de WordPress para ver la ficha completa del plugin: capturas de pantalla, preguntas frecuentes, instrucciones y compatibilidad.','IMPROVED: The GDPR banner message and offline schedule notice now use a visual editor. Add bold text, lists, or links directly from the text field.'=>'MEJORADO: El mensaje de banner GDPR y el aviso de programación offline ahora utilizan un editor visual. Añada texto en negrita, listas o enlaces directamente desde el campo de texto.','FIXED: The BravesChat panel no longer shows notices from other plugins. Only yours, without noise.'=>'ARREGLADO: El panel BravesChat ya no muestra avisos de otros plugins. Sólo el suyo, sin ruido.','ADDED: The panel detects if you have tools installed that could export the plugin code and warns you. An extra layer of protection.'=>'AÑADIDO: El panel detecta si tienes instaladas herramientas que podrían exportar el código del plugin y te avisa. Una capa extra de protección.','Feb 26, 2026'=>'26 de febrero de 2026','Conversation history'=>'Historia de la conversación','ADDED: New <strong>History</strong> section: access all conversations your agent has had with your visitors.'=>'AÑADIDO: Nueva sección <strong>Historial</strong>: accede a todas las conversaciones que tu agente ha mantenido con tus visitantes.','ADDED: Open any conversation with a click and read each message as it happened, in a clear chat interface.'=>'AÑADIDO: Abre cualquier conversación con un clic y lee cada mensaje tal y como sucedió, en una interfaz de chat clara.','ADDED: Export the full history to <strong>CSV</strong> with one click to analyze it in Excel, import it to your CRM, or share it with your team.'=>'AÑADIDO: Exporte el historial completo a <strong>CSV</strong> con un solo clic para analizarlo en Excel, importarlo a su CRM o compartirlo con su equipo.','IMPROVED: Your customers\' messages are shown exactly as they wrote them, without noise that makes reading harder.'=>'MEJORADO: Los mensajes de sus clientes se muestran exactamente como los escribieron, sin ruidos que dificulten la lectura.','IMPROVED: Each row groups all messages from the conversation so you see the full context.'=>'MEJORADO: Cada fila agrupa todos los mensajes de la conversación para que veas el contexto completo.','Feb 23, 2026'=>'23 de febrero de 2026','Automatic ZIP on every release'=>'ZIP automático en cada versión','ADDED: Every time we publish a version, the install-ready ZIP is generated automatically on GitHub. No manual steps.'=>'AÑADIDO: Cada vez que publicamos una versión, el ZIP listo para instalar se genera automáticamente en GitHub. Sin pasos manuales.','FIXED: The automatic ZIP generation process was not executing correctly in previous versions.'=>'CORREGIDO: El proceso de generación automática de ZIP no se ejecutaba correctamente en versiones anteriores.','Feb 20, 2026'=>'20 de febrero de 2026','Chat ignores your theme styles'=>'El chat ignora los estilos de tu tema','IMPROVED: The chat no longer inherits styles from the active theme. Buttons, inputs, and text look the same regardless of what theme you have installed.'=>'MEJORADO: El chat ya no hereda estilos del tema activo. Los botones, las entradas y el texto tienen el mismo aspecto independientemente del tema que tengas instalado.','IMPROVED: The Montserrat font applies to all chat elements: modal, full screen, and GDPR banner.'=>'MEJORADO: La fuente Montserrat se aplica a todos los elementos del chat: modal, pantalla completa y banner GDPR.','FIXED: The chat in center position was displayed offset on some themes. It now centers correctly.'=>'CORREGIDO: El chat en posición central se mostraba desplazado en algunos temas. Ahora se centra correctamente.','FIXED: The bottom-left position in modal mode was misaligned on certain screen sizes.'=>'CORREGIDO: La posición inferior izquierda en modo modal estaba desalineada en ciertos tamaños de pantalla.','IMPROVED: Each panel section has its own title in the browser tab.'=>'MEJORADO: Cada sección del panel tiene su propio título en la pestaña del navegador.','IMPROVED: When you uninstall the plugin, your settings are preserved in case you reinstall later.'=>'MEJORADO: Al desinstalar el plugin, se conserva la configuración por si se vuelve a instalar más tarde.','Feb 16, 2026'=>'16 de febrero de 2026','Real-time Markdown'=>'Markdown en tiempo real','IMPROVED: Agent responses render in real time with Markdown formatting. Bold, lists, and links appear as they arrive.'=>'MEJORADO: Las respuestas de los agentes se muestran en tiempo real con formato Markdown. Las negritas, las listas y los enlaces aparecen a medida que llegan.','FIXED: After sending a message, the cursor returns automatically to the text field. You can keep typing without clicking.'=>'ARREGLADO: Después de enviar un mensaje, el cursor vuelve automáticamente al campo de texto. Puede seguir escribiendo sin hacer clic.','Control the typing speed'=>'Controla la velocidad de escritura','ADDED: Slider to adjust the speed at which the agent "types" its responses. From slow and deliberate to near-instant.'=>'AÑADIDO: Control deslizante para ajustar la velocidad a la que el agente "teclea" sus respuestas. De lenta y deliberada a casi instantánea.','ADDED: The GDPR banner now accepts rich text. You can add bold text, lists, or links directly from the text field.'=>'AÑADIDO: El banner GDPR ahora acepta texto enriquecido. Puede añadir texto en negrita, listas o enlaces directamente desde el campo de texto.','ADDED: The chat font loads from your own server, with no dependency on external services.'=>'AÑADIDO: La fuente de chat se carga desde su propio servidor, sin depender de servicios externos.','FIXED: The chat scroll moves down automatically when a new message arrives. The GDPR banner displays correctly on all themes.'=>'CORREGIDO: El scroll del chat se desplaza automáticamente hacia abajo cuando llega un nuevo mensaje. El banner GDPR se muestra correctamente en todos los temas.','Feb 14, 2026'=>'14 de febrero de 2026','BravesChat iA 2.0'=>'BravesChat iA 2.0','ADDED: The plugin is renamed BravesChat iA with a fully rebuilt architecture from top to bottom.'=>'AÑADIDO: El plugin pasa a llamarse BravesChat iA con una arquitectura totalmente reconstruida de arriba a abajo.','ADDED: Button to maximize the chat. The user can expand it to full screen at any time.'=>'AÑADIDO: Botón para maximizar el chat. El usuario puede ampliarlo a pantalla completa en cualquier momento.','ADDED: The text area grows automatically when typing multiple lines, without overflowing the chat.'=>'AÑADIDO: El área de texto crece automáticamente al escribir varias líneas, sin desbordar el chat.','ADDED: After interacting, the chat bubble minimizes into a compact pill so it stays out of the way.'=>'AÑADIDO: Después de interactuar, la burbuja de chat se minimiza en una pastilla compacta para que no estorbe.','IMPROVED: Updated visual identity with BravesChat corporate colors.'=>'MEJORADO: Identidad visual actualizada con los colores corporativos de BravesChat.','IMPROVED: Message bubbles no longer cut text or show odd borders.'=>'MEJORADO: Las burbujas de mensajes ya no cortan el texto ni muestran bordes extraños.','IMPROVED: The send message icon is now a custom white design.'=>'MEJORADO: El icono de enviar mensaje tiene ahora un diseño blanco personalizado.','IMPROVED: The floating button tooltip defaults to "Talk to our AI assistant".'=>'MEJORADO: El tooltip del botón flotante es por defecto "Habla con nuestro asistente de IA".','FIXED: The send button no longer stays locked in unexpected situations.'=>'CORREGIDO: El botón de enviar ya no se queda bloqueado en situaciones inesperadas.','FIXED: When saving Excluded Pages settings, the selection was no longer lost.'=>'CORREGIDO: Al guardar la configuración de Páginas Excluidas, ya no se perdía la selección.','FIXED: The N8N integration no longer sent extra data that could confuse the agent.'=>'CORREGIDO: La integración N8N ya no enviaba datos extra que podían confundir al agente.','FIXED: When saving settings from any section, values configured on other pages were no longer lost.'=>'CORREGIDO: Al guardar la configuración de cualquier sección, ya no se perdían los valores configurados en otras páginas.','Nov 17, 2025'=>'17 de noviembre de 2025','Customizable tooltip'=>'Información sobre herramientas personalizable','ADDED: Text field to customize the message that appears when hovering over the floating chat button.'=>'AÑADIDO: Campo de texto para personalizar el mensaje que aparece al pasar el ratón por encima del botón flotante del chat.','ADDED: On activation, the plugin automatically detects older installed versions, deactivates them, and cleans up outdated files. No settings are lost.'=>'AÑADIDO: Al activarse, el plugin detecta automáticamente las versiones anteriores instaladas, las desactiva y limpia los archivos obsoletos. No se pierde ninguna configuración.','IMPROVED: The default floating button icon color changes to light gray for better contrast on dark backgrounds.'=>'MEJORADO: El color por defecto del icono del botón flotante cambia a gris claro para un mejor contraste en fondos oscuros.','IMPROVED: Appearance options are better organized. The tooltip appears right before the icon selector.'=>'MEJORADO: Las opciones de apariencia están mejor organizadas. El tooltip aparece justo antes del selector de iconos.','FIXED: Critical error that prevented WordPress from loading when two plugin versions were installed simultaneously.'=>'CORREGIDO: Error crítico que impedía cargar WordPress cuando se instalaban simultáneamente dos versiones del plugin.','FIXED: The icon color was not applied correctly when editing appearance settings.'=>'CORREGIDO: El color del icono no se aplicaba correctamente al editar los ajustes de apariencia.','Oct 26, 2025'=>'26 de octubre de 2025','Color and icon customization'=>'Personalización de colores e iconos','ADDED: Complete color customization system from the panel: bubble, primary color, background, and chat text.'=>'AÑADIDO: Completo sistema de personalización de colores desde el panel: burbuja, color primario, fondo y texto del chat.','ADDED: Native color picker synced with a hex text field. Type the exact code or use the visual picker.'=>'AÑADIDO: Selector de color nativo sincronizado con un campo de texto hexadecimal. Escriba el código exacto o utilice el selector visual.','ADDED: Color palette automatically extracted from the active theme, plus a default palette of 8 colors.'=>'AÑADIDO: Paleta de colores extraída automáticamente del tema activo, más una paleta por defecto de 8 colores.','ADDED: Four icons for the floating button: Robot, Circle, Happy, and Bubble.'=>'AÑADIDO: Cuatro iconos para el botón flotante: Robot, Círculo, Feliz y Burbuja.','IMPROVED: Color palettes can be expanded and collapsed with smooth animation to avoid screen clutter.'=>'MEJORADO: Las paletas de colores se pueden expandir y contraer con una animación suave para evitar el desorden de la pantalla.','IMPROVED: The icon selector uses a horizontal tab layout — clearer and faster to use.'=>'MEJORADO: El selector de iconos utiliza un diseño de pestañas horizontal: más claro y rápido de usar.','IMPROVED: The Appearance panel is responsive. Selectors reorganize into two columns on small screens.'=>'MEJORADO: El panel Apariencia es responsivo. Los selectores se reorganizan en dos columnas en pantallas pequeñas.','FIXED: Lottie Player dependency removed — it was loaded from an external CDN. The chat button no longer fails without an internet connection.'=>'CORREGIDO: Dependencia de Lottie Player eliminada - se cargaba desde un CDN externo. El botón de chat ya no falla sin conexión a internet.','FIXED: The floating button now uses a solid color instead of the gradient that caused visual inconsistencies.'=>'CORREGIDO: El botón flotante ahora utiliza un color sólido en lugar del gradiente que causaba inconsistencias visuales.','FIXED: The button image changed from animation to static SVG. Faster and no console errors.'=>'CORREGIDO: La imagen del botón cambió de animación a SVG estático. Más rápido y sin errores de consola.','Oct 25, 2025'=>'25 de octubre de 2025','Complete and functional panel'=>'Panel completo y funcional','FIXED: Configuration fields were not showing on some panel pages. They now appear correctly in all sections.'=>'CORREGIDO: Los campos de configuración no se mostraban en algunas páginas del panel. Ahora aparecen correctamente en todas las secciones.','FIXED: When saving from any settings page, values configured in other sections were no longer cleared.'=>'CORREGIDO: Al guardar desde cualquier página de configuración, ya no se borraban los valores configurados en otras secciones.','FIXED: The sidebar menu icon showed gray instead of white when selected.'=>'CORREGIDO: El icono del menú de la barra lateral se mostraba gris en lugar de blanco al seleccionarlo.','ADDED: Successful save notifications disappear automatically after a few seconds, with smooth animation.'=>'AÑADIDO: Las notificaciones de guardado correcto desaparecen automáticamente después de unos segundos, con una animación suave.','IMPROVED: Sidebar icons updated to solid versions for better readability.'=>'MEJORADO: Iconos de la barra lateral actualizados a versiones sólidas para una mejor legibilidad.','IMPROVED: Info cards are now clickable with external links.'=>'MEJORADO: Ahora se puede hacer clic en las tarjetas de información con enlaces externos.','IMPROVED: All panel checkboxes use the toggle style from the Bentō design.'=>'MEJORADO: Todas las casillas de verificación del panel utilizan el estilo toggle del diseño Bentō.','Oct 24, 2025'=>'24 de octubre de 2025','Full admin panel redesign'=>'Rediseño completo del panel de administración','ADDED: Admin panel redesigned with the Bentō style — clean, modular, and easy to navigate.'=>'AÑADIDO: Panel de administración rediseñado con el estilo Bentō: limpio, modular y fácil de navegar.','ADDED: Five independent sections: Dashboard, Settings, Appearance, Availability, and Privacy.'=>'AÑADIDO: Cinco secciones independientes: Panel de control, Configuración, Apariencia, Disponibilidad y Privacidad.','ADDED: Shared sidebar across all panel pages for consistent navigation.'=>'AÑADIDO: Barra lateral compartida en todas las páginas del panel para una navegación coherente.','Oct 23, 2025'=>'23 de octubre de 2025','Brand change'=>'Cambio de marca','IMPROVED: The plugin updates its brand from Weblandia to BravesLab — all URLs and references updated to braveslab.com.'=>'MEJORADO: El plugin actualiza su marca de Weblandia a BravesLab - todas las URLs y referencias actualizadas a braveslab.com.','Oct 16, 2025'=>'16 de octubre de 2025','Cookie system and GDPR'=>'Sistema de cookies y GDPR','ADDED: Unique user identification system via browser fingerprinting, without storing personal data.'=>'AÑADIDO: Sistema único de identificación de usuarios mediante huella digital del navegador, sin almacenamiento de datos personales.','ADDED: Configurable GDPR consent banner — blocks the chat until the user accepts.'=>'AÑADIDO: Banner de consentimiento GDPR configurable - bloquea el chat hasta que el usuario acepta.','ADDED: If cookies are blocked by the browser, the chat history is saved in local memory as a fallback.'=>'AÑADIDO: Si el navegador bloquea las cookies, el historial de chat se guarda en la memoria local como alternativa.','Oct 1, 2025'=>'1 de octubre de 2025','Schedules and excluded pages'=>'Horarios y páginas excluidas','ADDED: Define the hours when the chat is available, with timezone support.'=>'AÑADIDO: Define las horas en las que el chat está disponible, con soporte de zona horaria.','ADDED: Automatic out-of-hours message. The agent responds with your text when unavailable.'=>'AÑADIDO: Mensaje automático fuera de horario. El agente responde con su texto cuando no está disponible.','ADDED: Excluded pages selector. Choose which pages on your site should not show the chat.'=>'AÑADIDO: Selector de páginas excluidas. Elija qué páginas de su sitio no deben mostrar el chat.','ADDED: Authentication token to secure communication with your N8N agent.'=>'AÑADIDO: Token de autenticación para asegurar la comunicación con su agente N8N.','IMPROVED: Webhook configuration is more flexible and validates the URL before saving.'=>'MEJORADO: La configuración de Webhook es más flexible y valida la URL antes de guardar.','Sep 15, 2025'=>'15 de septiembre de 2025','Initial release'=>'Lanzamiento inicial','ADDED: AI chat widget integrated in WordPress via Gutenberg block.'=>'AÑADIDO: Widget de chat AI integrado en WordPress a través del bloque Gutenberg.','ADDED: Direct connection to N8N workflows via configurable webhook.'=>'AÑADIDO: Conexión directa a flujos de trabajo N8N mediante webhook configurable.','ADDED: Two display modes: floating modal and full screen.'=>'AÑADIDO: Dos modos de visualización: modal flotante y pantalla completa.','ADDED: Configurable floating button positioning: right, left, or center.'=>'AÑADIDO: Posicionamiento configurable del botón flotante: derecha, izquierda o centro.','ADDED: Welcome messages, chat title and subtitle customizable from the panel.'=>'AÑADIDO: Mensajes de bienvenida, título y subtítulo del chat personalizables desde el panel.','ADDED: Ready for translation into any language.'=>'AÑADIDO: Listo para su traducción a cualquier idioma.','Almost there! Connect the Webhook URL in Settings so your agent can start working.'=>'¡Ya casi está! Conecta la URL del Webhook en Ajustes para que tu agente pueda empezar a trabajar.','Settings saved successfully.'=>'Ajustes guardados correctamente.','Customize the visual appearance of the chat: titles, messages, position and display mode.'=>'Personaliza el aspecto visual del chat: títulos, mensajes, posición y modo de visualización.','Chat Appearance'=>'Aspecto del chat','Floating Bubble'=>'Burbuja flotante','Full Screen'=>'Pantalla completa','Mixed Display'=>'Pantalla mixta','Select the visual behavior that best fits your website design.'=>'Seleccione el comportamiento visual que mejor se adapte al diseño de su sitio web.','Mixed Mode: floating bubble on the whole website, full screen on pages with the Gutenberg block.'=>'Modo mixto: burbuja flotante en todo el sitio web, pantalla completa en las páginas con el bloque Gutenberg.','Display Mode'=>'Modo de visualización','Defines how the window is presented to the visitor.'=>'Define cómo se presenta la ventana al visitante.','Basic Skin'=>'Piel básica','Braves Skin'=>'Piel de los Bravos','Choose the design template that best fits your brand.'=>'Elija la plantilla de diseño que mejor se adapte a su marca.','Chat Design'=>'Diseño de chat','Customize the visual style of the Agent.'=>'Personalize el estilo visual del Agente.','Select image'=>'Seleccionar imagen','Use image'=>'Utilizar la imagen','Upload image'=>'Cargar imagen','Remove image'=>'Eliminar imagen','Upload a custom image (1:1) for the floating button.%sOnly visible in the Braves skin.'=>'Sube una imagen personalizada (1:1) para el botón flotante.%sólo visible en la skin Braves.','Bubble Image'=>'Imagen de burbuja','Replace the default icon with your own image.'=>'Sustituye el icono predeterminado por tu propia imagen.','Need help?'=>'¿Necesita ayuda?','Text that appears next to the bubble image (only for Braves skin).'=>'Texto que aparece junto a la imagen de la burbuja (sólo para la piel Braves).','Bubble Text'=>'Texto burbuja','Message that accompanies the chat button.'=>'Mensaje que acompaña al botón de chat.','BravesLab AI Assistant'=>'Asistente de IA de BravesLab','Main title shown in the chat header.'=>'Título principal mostrado en la cabecera del chat.','Header Title'=>'Título de la cabecera','The main title users will see in the chat.'=>'El título principal que los usuarios verán en el chat.','Chatting with Charlie'=>'Charlando con Charlie','Text that appears with animation next to the avatar when the chat opens.'=>'Texto que aparece con animación junto al avatar cuando se abre el chat.','Status Text (Animated)'=>'Texto de estado (animado)','Text that unfolds next to the avatar.'=>'Texto que se despliega junto al avatar.','Artificial Intelligence Marketing Agency'=>'Agencia de marketing de inteligencia artificial','Subtitle shown below the main title.'=>'Subtítulo que aparece debajo del título principal.','Header Subtitle'=>'Subtítulo de cabecera','Descriptive text that complements the title.'=>'Texto descriptivo que complementa el título.','E.g.: Charlie'=>'Por ejemplo Charlie','This name will be used in the history to organize and filter conversations.'=>'Este nombre se utilizará en el historial para organizar y filtrar las conversaciones.','Agent Name'=>'Nombre del agente','Defines how you will identify your agent in your records.'=>'Define cómo identificará a su agente en sus registros.','Hello! I\'m the BravesLab assistant, your Artificial Intelligence Marketing Agency. We integrate AI into businesses to multiply results. How can we help you?'=>'¡Hola! Soy el asistente de BravesLab, tu Agencia de Marketing con Inteligencia Artificial. Integramos la IA en las empresas para multiplicar los resultados. ¿En qué podemos ayudarte?','Hello! How can we help you?'=>'Hola, ¿en qué podemos ayudarle?','Initial message the user will see when opening the chat.'=>'Mensaje inicial que verá el usuario al abrir el chat.','Welcome Message'=>'Mensaje de bienvenida','The first message the user will see in the chat.'=>'El primer mensaje que el usuario verá en el chat.','Bottom right'=>'Abajo a la derecha','Bottom left'=>'Abajo a la izquierda','Center'=>'Centro','Position of the chat widget on the screen.'=>'Posición del widget de chat en la pantalla.','Chat Position'=>'Posición en el chat','Where the chat button will appear on the screen.'=>'Dónde aparecerá el botón de chat en la pantalla.','Talk to our AI assistant'=>'Hable con nuestro asistente','Text that will appear when hovering over the floating button.'=>'Texto que aparecerá al pasar el ratón por encima del botón flotante.','Button Tooltip'=>'Botón Tooltip','Message shown when hovering over the button.'=>'Mensaje que se muestra al pasar el ratón por encima del botón.','Original'=>'Original','Circle'=>'Círculo','Happy'=>'Feliz','Bubble'=>'Burbuja','Button Icon'=>'Icono del botón','Icon that will appear in the floating chat button.'=>'Icono que aparecerá en el botón flotante del chat.','Select custom color'=>'Seleccionar color personalizado','Theme colors'=>'Colores temáticos','SVG icon color in the floating chat button.'=>'Color del icono SVG en el botón flotante del chat.','Icon Color'=>'Icono Color','Color that will be applied to the button SVG icon.'=>'Color que se aplicará al icono SVG del botón.','Custom Colors'=>'Colores personalizados','Color of the floating button (bubble) of the chat.'=>'Color del botón flotante (burbuja) del chat.','Bubble Color'=>'Color burbuja','Color of the floating button that opens the chat.'=>'Color del botón flotante que abre el chat.','Color of the header and assistant messages.'=>'Color de la cabecera y de los mensajes asistentes.','Primary Color'=>'Color principal','Main color used in the chat header.'=>'Color principal utilizado en la cabecera del chat.','Background color of the chat window.'=>'Color de fondo de la ventana de chat.','Background Color'=>'Color de fondo','Background color of the message area.'=>'Color de fondo del área de mensajes.','Color of the message text.'=>'Color del texto del mensaje.','Text Color'=>'Color del texto','Color of the main text in messages.'=>'Color del texto principal en los mensajes.','Configure the chat availability schedule. When enabled, the chat will only be available during the specified hours.'=>'Configure el horario de disponibilidad del chat. Cuando esté activado, el chat solo estará disponible durante las horas especificadas.','Schedule Settings'=>'Ajustes de horario','Enable business hours restriction'=>'Activar la restricción del horario comercial','Enable Schedule'=>'Activar horario','Activate schedule restrictions for the chat.'=>'Activar restricciones de horario para el chat.','Reference timezone for the configured schedule.'=>'Zona horaria de referencia para el horario configurado.','Timezone'=>'Zona horaria','Reference timezone for the schedule.'=>'Zona horaria de referencia para el horario.','Start time of the business hours (24h format).'=>'Hora de inicio del horario comercial (formato 24h).','Start Time'=>'Hora de inicio','Time when the chat becomes available.'=>'Hora a la que está disponible el chat.','End time of the business hours (24h format).'=>'Hora de finalización del horario comercial (formato 24h).','End Time'=>'Fin de los tiempos','Time when the chat stops being available.'=>'Hora en la que el chat deja de estar disponible.','Off-Hours Message'=>'Mensaje fuera de horario','Text users will see outside business hours.'=>'Los usuarios de texto verán fuera del horario comercial.','Message shown when the user tries to use the chat outside business hours.'=>'Mensaje que se muestra cuando el usuario intenta utilizar el chat fuera del horario comercial.','Almost there.'=>'Ya casi está.','Without the Webhook URL, the chat cannot communicate with N8N. Go to Settings and link your flow to activate the AI.'=>'Sin la URL Webhook, el chat no puede comunicarse con N8N. Vaya a Ajustes y vincule su flujo para activar la IA.','Your agent\'s control center. From here you manage how your AI interacts with the world.'=>'El centro de control de tu agente. Desde aquí gestionas cómo interactúa tu IA con el mundo.','Chat Active'=>'Chat activo','Chat Offline'=>'Chat fuera de línea','Chat disabled — enable it in Settings so your visitors can use it.'=>'Chat desactivado - actívalo en Configuración para que tus visitantes puedan utilizarlo.','Your agent is online. Everything is in order, the AI is ready to assist your customers.'=>'Su agente está en línea. Todo está en orden, la IA está lista para atender a sus clientes.','Your agent is not configured yet. Set up the webhook to get started.'=>'Su agente aún no está configurado. Configure el webhook para empezar.','View live'=>'Ver en directo','Go to General Settings'=>'Ir a Ajustes generales','Brain and style. Adjust what the chat says, how it says it, and what it looks like.'=>'Cerebro y estilo. Ajusta lo que dice el chat, cómo lo dice y qué aspecto tiene.','Customize'=>'Personalizar','Documentation'=>'Documentación','Need help? Step-by-step guide to get the most out of all BravesChat features.'=>'¿Necesitas ayuda? Guía paso a paso para aprovechar al máximo todas las funciones de BravesChat.','Open manual'=>'Abrir manual','Quick Actions'=>'Acciones rápidas','Change Design'=>'Cambiar el diseño','Connect to N8N'=>'Conectar con N8N','Dark Mode'=>'Modo oscuro','Configure the cookie consent banner to comply with GDPR regulations.<br/>The system uses persistent cookies with browser fingerprinting.'=>'Configura el banner de consentimiento de cookies para cumplir con la normativa GDPR.<br/>El sistema utiliza cookies persistentes con huella digital del navegador.','GDPR / Cookie Compliance'=>'Cumplimiento de GDPR / Cookies','Show cookie consent banner. Consent is saved in localStorage.'=>'Mostrar banner de consentimiento de cookies. El consentimiento se guarda en localStorage.','Enable GDPR Banner'=>'Activar el banner GDPR','Shows a consent banner before creating cookies.'=>'Muestra un banner de consentimiento antes de crear cookies.','This site uses cookies to improve your experience and provide a personalized chat service. By continuing to browse, you accept our cookie policy.'=>'Este sitio utiliza cookies para mejorar su experiencia y ofrecerle un servicio de chat personalizado. Al continuar navegando, aceptas nuestra política de cookies.','Banner Message'=>'Banner Mensaje','Informational text about cookie usage in the chat.'=>'Texto informativo sobre el uso de cookies en el chat.','Message shown in the cookie banner. You can use bold, italics and links.'=>'Mensaje mostrado en el banner de cookies. Puede utilizar negrita, cursiva y enlaces.','Text for the cookie acceptance button (e.g.: "Accept", "Got it", "I agree").'=>'Texto para el botón de aceptación de cookies (por ejemplo: "Aceptar", "Entendido", "Estoy de acuerdo").','Accept Button Text'=>'Texto del botón Aceptar','Label for the cookie acceptance button.'=>'Etiqueta para el botón de aceptación de cookies.','Invalid webhook URL: only HTTP and HTTPS are allowed.'=>'URL de webhook no válida: sólo se permiten HTTP y HTTPS.','HTTP error %d when connecting to the server.'=>'Error HTTP %d al conectar con el servidor.','The webhook responded with an empty body. Check that the N8N flow is active and returning data.'=>'El webhook respondió con un cuerpo vacío. Comprueba que el flujo N8N está activo y devuelve datos.','The webhook response is not valid JSON.'=>'La respuesta del webhook no es un JSON válido.','Conversations recorded with your AI agent.'=>'Conversaciones grabadas con su agente de IA.','Webhook not configured:'=>'Webhook no configurado:','Configure the history webhook URL in <a href="%s">Settings</a>.'=>'Configura la URL del webhook del historial en <a href="%s">Configuración</a>.','No conversations found or there is a connection error.'=>'No se han encontrado conversaciones o hay un error de conexión.','%d conversation found'=>'%d conversación encontrada' . "\0" . '%d conversaciones encontradas','Download CSV'=>'Descargar CSV','Contact'=>'Póngase en contacto con','Excerpt'=>'Extracto','Date'=>'Fecha','(No messages)'=>'(Sin mensajes)','Unknown'=>'Desconocido','Close'=>'Cerrar','Chat Conversation'=>'Conversación por chat','Agent Settings'=>'Configuración del agente','Manage the connection, visibility and behavior of your AI Agent.'=>'Gestione la conexión, la visibilidad y el comportamiento de su Agente AI.','General Settings'=>'Ajustes generales','Show the chat on all pages of the website'=>'Mostrar el chat en todas las páginas del sitio web','Global Activation'=>'Activación mundial','Enable the agent on all pages of the website.'=>'Habilitar el agente en todas las páginas del sitio web.','N8N webhook URL to process chat messages.'=>'URL del webhook N8N para procesar mensajes de chat.','Webhook URL'=>'URL del webhook','The bridge between your website and your N8N system.'=>'El puente entre su sitio web y su sistema N8N.','No authentication'=>'Sin autenticación','Custom header (Header Auth)'=>'Encabezado personalizado (Header Auth)','Basic Auth (username + password)'=>'Autenticación básica (nombre de usuario + contraseña)','Choose the authentication type configured in your N8N Webhook or Chat Trigger node.'=>'Elija el tipo de autenticación configurado en su nodo N8N Webhook o Chat Trigger.','Authentication Type'=>'Tipo de autenticación','Security method to protect access to the webhook.'=>'Método de seguridad para proteger el acceso al webhook.','Credentials'=>'Credenciales','Agent Identity (User) <br/>Security Token (Password).'=>'Identidad del agente (usuario) <br/>Token 